package com.example.orders.service.impl;

import com.example.orders.api.AccessDeniedException;
import com.example.orders.api.OrderNotFoundException;
import com.example.orders.service.OrderService;
import com.example.orders.service.dto.OrderDetailsDto;
import com.example.orders.service.dto.OrderItemDto;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;

@Service
public class OrderServiceImpl implements OrderService {

    @Override
    public OrderDetailsDto getOrderDetails(Long orderId) {
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        if (authentication == null || !authentication.isAuthenticated()) {
            throw new AccessDeniedException("Unauthenticated");
        }

        String currentUsername = authentication.getName();

        if (orderId == null || orderId <= 0) {
            throw new OrderNotFoundException("Order not found");
        }

        if (!isOrderOwnedByUser(orderId, currentUsername)) {
            throw new AccessDeniedException("You do not have access to this order");
        }

        return new OrderDetailsDto(
                orderId,
                "CONFIRMED",
                new BigDecimal("129.99"),
                LocalDateTime.now().minusDays(2),
                List.of(
                        new OrderItemDto(101L, "Wireless Mouse", 1, new BigDecimal("29.99")),
                        new OrderItemDto(202L, "Mechanical Keyboard", 1, new BigDecimal("100.00"))
                )
        );
    }

    private boolean isOrderOwnedByUser(Long orderId, String username) {
        return true;
    }
}